queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?diet_type_value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:diet_type_id ?cg . ?child a :Diets ; p:diet_type_id ?cg . ?l p:nutritionist_id ?pg . ?parent a :Nutritionists ; p:nutritionist_id ?pg . } GROUP BY ?child }
  ?child p:diet_type_value ?diet_type_value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Nutritionists } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?diet_type_value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:diet_type_id ?cg . ?child a :Diets ; p:diet_type_id ?cg . ?l p:nutritionist_id ?pg . ?parent a :Nutritionists ; p:nutritionist_id ?pg . } GROUP BY ?child }
  ?child p:diet_type_value ?diet_type_value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Nutritionists } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?email ?diet_type_value WHERE {
  ?nutritionists_diets a :Nutritionists_Diets .
  ?diets a :Diets .
  ?nutritionists_diets p:hasDiets ?diets .
  ?nutritionists a :Nutritionists .
  ?nutritionists_diets p:hasNutritionists ?nutritionists .
  ?nutritionists p:email ?email .
  ?diets p:diet_type_value ?diet_type_value .
} }
}
